1	package graph
2	
3	import (
4		"slices"
5		"strings"
6	
7		metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
8		"k8s.io/apimachinery/pkg/types"
9		"k8s.io/apimachinery/pkg/util/validation/field"
10		"sigs.k8s.io/controller-runtime/pkg/client"
11		v1 "sigs.k8s.io/gateway-api/apis/v1"
12		"sigs.k8s.io/gateway-api/pkg/consts"
13		"sigs.k8s.io/gateway-api/pkg/features"
14	
15		"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/state/conditions"
16		"github.com/nginx/nginx-gateway-fabric/v2/internal/framework/helpers"
17		"github.com/nginx/nginx-gateway-fabric/v2/internal/framework/kinds"
18	)
19	
20	var gatewayCRDs = map[string]apiVersion{
21		"gatewayclasses.gateway.networking.k8s.io":     {},
22		"gateways.gateway.networking.k8s.io":           {},
23		"httproutes.gateway.networking.k8s.io":         {},
24		"referencegrants.gateway.networking.k8s.io":    {},
25		"backendtlspolicies.gateway.networking.k8s.io": {},
26		"grpcroutes.gateway.networking.k8s.io":         {},
27		"tlsroutes.gateway.networking.k8s.io":          {},
28	}
29	
30	// GatewayClass represents the GatewayClass resource.
31	type GatewayClass struct {
32		// Source is the source resource.
33		Source *v1.GatewayClass
34		// NginxProxy is the NginxProxy resource referenced by this GatewayClass.
35		NginxProxy *NginxProxy
36		// Conditions include Conditions for the GatewayClass.
37		Conditions []conditions.Condition
38		// Valid shows whether the GatewayClass is valid.
39		Valid bool
40		// ExperimentalSupported indicates whether experimental features are supported.
41		ExperimentalSupported bool
42		// BestEffort indicates whether the Gateway API CRD versions are not supported,
43		// but we are attempting to generate configuration.
44		BestEffort bool
45	}
46	
47	// processedGatewayClasses holds the resources that belong to NGF.
48	type processedGatewayClasses struct {
49		Winner  *v1.GatewayClass
50		Ignored map[types.NamespacedName]*v1.GatewayClass
51	}
52	
53	// processGatewayClasses returns the "Winner" GatewayClass, which is defined in
54	// the command-line argument and references this controller, and a list of "Ignored" GatewayClasses
55	// that reference this controller, but are not named in the command-line argument.
56	// Also returns a boolean that says whether the GatewayClass defined
57	// in the command-line argument exists, regardless of which controller it references.
58	func processGatewayClasses(
59		gcs map[types.NamespacedName]*v1.GatewayClass,
60		gcName string,
61		controllerName string,
62	) (processedGatewayClasses, bool) {
63		processedGwClasses := processedGatewayClasses{}
64	
65		var gcExists bool
66		for _, gc := range gcs {
67			if gc.Name == gcName {
68				gcExists = true
69				if string(gc.Spec.ControllerName) == controllerName {
70					processedGwClasses.Winner = gc
71				}
72			} else if string(gc.Spec.ControllerName) == controllerName {
73				if processedGwClasses.Ignored == nil {
74					processedGwClasses.Ignored = make(map[types.NamespacedName]*v1.GatewayClass)
75				}
76				processedGwClasses.Ignored[client.ObjectKeyFromObject(gc)] = gc
77			}
78		}
79	
80		return processedGwClasses, gcExists
81	}
82	
83	func buildGatewayClass(
84		gc *v1.GatewayClass,
85		nps map[types.NamespacedName]*NginxProxy,
86		crdVersions map[types.NamespacedName]*metav1.PartialObjectMetadata,
87		experimentalEnabled bool,
88	) *GatewayClass {
89		if gc == nil {
90			return nil
91		}
92	
93		var np *NginxProxy
94		if gc.Spec.ParametersRef != nil {
95			np = getNginxProxyForGatewayClass(*gc.Spec.ParametersRef, nps)
96		}
97	
98		conds, valid, crdExperimental, bestEffort := validateGatewayClass(gc, np, crdVersions)
99	
100		// Experimental features are supported only if both the config flag AND CRD channel are experimental
101		experimental := experimentalEnabled && crdExperimental
102	
