52	// processGateways determines which Gateway resources belong to NGF (determined by the Gateway GatewayClassName field).
53	func processGateways(
54		gws map[types.NamespacedName]*v1.Gateway,
55		gcName string,
56	) map[types.NamespacedName]*v1.Gateway {
57		referencedGws := make(map[types.NamespacedName]*v1.Gateway)
58	
59		for gwNsName, gw := range gws {
60			if string(gw.Spec.GatewayClassName) != gcName {
61				continue
62			}
63	
64			referencedGws[gwNsName] = gw
65		}
66	
67		if len(referencedGws) == 0 {
68			return nil
69		}
70	
71		return referencedGws
