74	func buildGateways(
75		gws map[types.NamespacedName]*v1.Gateway,
76		resourceResolver resolver.Resolver,
77		gc *GatewayClass,
78		refGrantResolver *referenceGrantResolver,
79		nps map[types.NamespacedName]*NginxProxy,
80	) map[types.NamespacedName]*Gateway {
81		if len(gws) == 0 {
82			return nil
83		}
84	
85		builtGateways := make(map[types.NamespacedName]*Gateway, len(gws))
86	
87		for gwNsName, gw := range gws {
88			var np *NginxProxy
89			var npNsName types.NamespacedName
90			var listenerNamespaces *v1.ListenerNamespaces
91			if gw.Spec.Infrastructure != nil && gw.Spec.Infrastructure.ParametersRef != nil {
