93				np = nps[npNsName]
94			}
95	
96			var gcNp *NginxProxy
97			if gc != nil {
98				gcNp = gc.NginxProxy
99			}
100	
101			effectiveNginxProxy := buildEffectiveNginxProxy(gcNp, np)
102	
103			conds, valid, secretRefNsName := validateGateway(gw, gc, np, resourceResolver, refGrantResolver)
104	
105			protectedPorts := buildProtectedPorts(effectiveNginxProxy)
106	
107			deploymentName := types.NamespacedName{
108				Namespace: gw.GetNamespace(),
109				Name:      controller.CreateNginxResourceName(gw.GetName(), string(gw.Spec.GatewayClassName)),
110			}
111	
112			if gw.Spec.AllowedListeners != nil && gw.Spec.AllowedListeners.Namespaces != nil {
113				listenerNamespaces = gw.Spec.AllowedListeners.Namespaces
114			}
115	
116			if !valid {
117				builtGateways[gwNsName] = &Gateway{
118					Source:              gw,
119					Valid:               false,
120					NginxProxy:          np,
121					EffectiveNginxProxy: effectiveNginxProxy,
122					Conditions:          conds,
123					DeploymentName:      deploymentName,
124					SecretRef:           secretRefNsName,
125					ListenerNamespaces:  listenerNamespaces,
126				}
127			} else {
128				gateway := &Gateway{
129					Source:              gw,
130					NginxProxy:          np,
131					EffectiveNginxProxy: effectiveNginxProxy,
132					Valid:               true,
133					Conditions:          conds,
134					DeploymentName:      deploymentName,
135					SecretRef:           secretRefNsName,
136					ListenerNamespaces:  listenerNamespaces,
137					ListenerFactory:     newListenerConfiguratorFactory(gw, resourceResolver, refGrantResolver, protectedPorts),
138				}
139				gateway.Listeners = buildListeners(gateway, gw.Spec.Listeners, gwNsName, types.NamespacedName{})
140				builtGateways[gwNsName] = gateway
