146	
147	// validateGatewayRefs validates both parametersRef and TLS fields.
148	func validateGatewayRefs(
149		gw *v1.Gateway,
150		npCfg *NginxProxy,
151		resourceResolver resolver.Resolver,
152		refGrantResolver *referenceGrantResolver,
153	) ([]conditions.Condition, *types.NamespacedName) {
154		if (gw.Spec.Infrastructure == nil || gw.Spec.Infrastructure.ParametersRef == nil) &&
155			(gw.Spec.TLS == nil || gw.Spec.TLS.Backend == nil) {
156			return nil, nil
157		}
158	
159		conds, parametersRefErrMsg := validateParametersRef(gw, npCfg)
160		paramsRefValid := len(conds) == 0
161	
162		var backendSecretNsName *types.NamespacedName
163		var backendTLSCond conditions.Condition
164	
165		if gw.Spec.TLS != nil {
166			path := field.NewPath("spec.tls")
167	
168			if gw.Spec.TLS.Backend != nil {
169				backendPath := path.Child("backend")
170				backendTLSCond, backendSecretNsName = validateGatewayTLSBackend(
171					gw,
172					backendPath,
173					resourceResolver,
174					refGrantResolver,
175				)
176			}
177		}
178		tlsValid := backendTLSCond == conditions.Condition{}
179	
180		switch {
181		case paramsRefValid && tlsValid:
182			conds = append(conds, conditions.NewGatewayResolvedRefs())
183		case !tlsValid:
184			conds = append(conds, backendTLSCond)
185		default:
186			conds = append(conds, conditions.NewGatewayRefInvalid(parametersRefErrMsg))
187		}
