199			ref := *gw.Spec.Infrastructure.ParametersRef
200			if _, ok := supportedParamKinds[string(ref.Kind)]; !ok {
201				err := field.NotSupported(path.Child("kind"), string(ref.Kind), []string{kinds.NginxProxy})
202				parametersRefErrMsg = helpers.CapitalizeString(err.Error())
203				conds = append(conds, conditions.NewGatewayInvalidParameters(parametersRefErrMsg))
204			} else if npCfg == nil {
205				err := field.NotFound(path.Child("name"), ref.Name)
206				parametersRefErrMsg = helpers.CapitalizeString(err.Error())
207				conds = append(conds, conditions.NewGatewayInvalidParameters(parametersRefErrMsg))
208			} else if !npCfg.Valid {
209				parametersRefErrMsg = helpers.CapitalizeString(npCfg.ErrMsgs.ToAggregate().Error())
210				conds = append(conds, conditions.NewGatewayInvalidParameters(parametersRefErrMsg))
211			}
212		}
213	
214		return conds, parametersRefErrMsg
215	}
216	
217	func validateGatewayTLSBackend(
218		gw *v1.Gateway,
219		path *field.Path,
220		resourceResolver resolver.Resolver,
221		refGrantResolver *referenceGrantResolver,
222	) (conditions.Condition, *types.NamespacedName) {
223		backend := gw.Spec.TLS.Backend
224		if backend.ClientCertificateRef == nil {
225			return conditions.Condition{}, nil
226		}
227	
228		if backend.ClientCertificateRef.Kind != nil &&
229			*backend.ClientCertificateRef.Kind != kinds.Secret {
230			valErr := field.NotSupported(
231				path.Child("clientCertificateRef", "kind"),
232				*backend.ClientCertificateRef.Kind, []string{kinds.Secret},
233			)
234			msg := helpers.CapitalizeString(valErr.Error())
235	
236			return conditions.NewGatewaySecretRefInvalid(msg), nil
237		}
238	
239		if backend.ClientCertificateRef.Group != nil &&
240			*backend.ClientCertificateRef.Group != "" && *backend.ClientCertificateRef.Group != "core" {
241			valErr := field.NotSupported(
242				path.Child("clientCertificateRef", "group"),
243				*backend.ClientCertificateRef.Group, []string{"core", ""},
244			)
245			msg := helpers.CapitalizeString(valErr.Error())
246	
247			return conditions.NewGatewaySecretRefInvalid(msg), nil
248		}
249	
250		secretNsName, secretNs := getGatewayCertSecretNsName(gw)
251		if err := resourceResolver.Resolve(resolver.ResourceTypeSecret, *secretNsName); err != nil {
252			valErr := field.Invalid(path.Child("clientCertificateRef"), secretNsName, err.Error())
253			msg := helpers.CapitalizeString(valErr.Error())
254	
255			return conditions.NewGatewaySecretRefInvalid(msg), nil
256		} else if secretNs != gw.Namespace {
257			if !refGrantResolver.refAllowed(toSecret(*secretNsName), fromGateway(gw.Namespace)) {
258				msg := fmt.Sprintf("secret ref %s not permitted by any ReferenceGrant", secretNsName)
259	
260				return conditions.NewGatewayRefNotPermitted(msg), nil
261			}
262		}
263	
264		return conditions.Condition{}, secretNsName
265	}
266	
267	func validateGateway(
268		gw *v1.Gateway,
269		gc *GatewayClass,
270		npCfg *NginxProxy,
271		resourceResolver resolver.Resolver,
272		refGrantResolver *referenceGrantResolver,
273	) ([]conditions.Condition, bool, *types.NamespacedName) {
274		var conds []conditions.Condition
275	
276		if gc == nil {
277			conds = append(conds, conditions.NewGatewayInvalid("The GatewayClass doesn't exist")...)
278		} else if !gc.Valid {
279			conds = append(conds, conditions.NewGatewayInvalid("The GatewayClass is invalid")...)
280		}
281	
282		// Set the unaccepted conditions here, because those make the gateway invalid. We set the unprogrammed conditions
283		// elsewhere, because those do not make the gateway invalid.
284		for _, address := range gw.Spec.Addresses {
285			if address.Type == nil {
286				conds = append(conds, conditions.NewGatewayUnsupportedAddress("The AddressType must be specified"))
287			} else if *address.Type != v1.IPAddressType {
288				conds = append(conds, conditions.NewGatewayUnsupportedAddress("Only AddressType IPAddress is supported"))
289			}
290		}
291	
292		// Evaluate validity before validating refs
293		valid := len(conds) == 0
294	
295		// Validate unsupported fields - these are warnings, don't affect validity
296		conds = append(conds, validateUnsupportedGatewayFields(gw)...)
297	
298		// Validate referenced resources
299		refsConds, secretRefNsName := validateGatewayRefs(gw, npCfg, resourceResolver, refGrantResolver)
300		conds = append(conds, refsConds...)
301	
302		return conds, valid, secretRefNsName
303	}
304	
305	// getGatewayCertSecretNsName returns the NamespacedName of the secret referenced by the Gateway for backend TLS.
306	func getGatewayCertSecretNsName(gw *v1.Gateway) (*types.NamespacedName, string) {
307		gatewayCert := gw.Spec.TLS.Backend.ClientCertificateRef
308		secretRefNs := gw.Namespace
309		if gatewayCert.Namespace != nil {
310			secretRefNs = string(*gatewayCert.Namespace)
311		}
312		return &types.NamespacedName{
313			Namespace: secretRefNs,
314			Name:      string(gatewayCert.Name),
315		}, secretRefNs
316	}
317	
318	// GetReferencedSnippetsFilters returns all SnippetsFilters that are referenced by routes attached to this Gateway.
319	func (g *Gateway) GetReferencedSnippetsFilters(
320		routes map[RouteKey]*L7Route,
321		allSnippetsFilters map[types.NamespacedName]*SnippetsFilter,
322	) map[types.NamespacedName]*SnippetsFilter {
323		if len(routes) == 0 || len(allSnippetsFilters) == 0 {
324			return nil
325		}
326	
327		gatewayNsName := client.ObjectKeyFromObject(g.Source)
328		referencedSnippetsFilters := make(map[types.NamespacedName]*SnippetsFilter)
329	
330		for _, route := range routes {
331			if !route.Valid || !g.isRouteAttachedToGateway(route, gatewayNsName) {
332				continue
333			}
334	
335			g.collectSnippetsFiltersFromRoute(route, allSnippetsFilters, referencedSnippetsFilters)
336		}
337	
338		if len(referencedSnippetsFilters) == 0 {
339			return nil
340		}
341	
342		return referencedSnippetsFilters
343	}
344	
345	// GetReferencedRateLimitPolicies returns all RateLimitPolicies that target routes attached to this Gateway.
346	// RateLimitPolicies that target the Gateway directly are excluded.
347	//
348	//nolint:gocyclo // complexity is acceptable for this function
349	func (g *Gateway) GetReferencedRateLimitPolicies(
350		routes map[RouteKey]*L7Route,
351		allPolicies map[PolicyKey]*Policy,
352	) map[PolicyKey]*Policy {
353		if len(allPolicies) == 0 {
354			return nil
355		}
356	
357		gatewayNsName := client.ObjectKeyFromObject(g.Source)
358		referencedRateLimitPolicies := make(map[PolicyKey]*Policy)
359	
360		// Create a lookup map of routes attached to this gateway for efficient checking
361		attachedRoutes := make(map[types.NamespacedName]struct{})
362		for _, route := range routes {
363			if !route.Valid || !g.isRouteAttachedToGateway(route, gatewayNsName) {
364				continue
365			}
366			routeNsName := client.ObjectKeyFromObject(route.Source)
367			attachedRoutes[routeNsName] = struct{}{}
368		}
369	
370		// Iterate through all policies and check their target references
371		for policyKey, policy := range allPolicies {
372			// Skip invalid policies or policies invalid for this gateway
373			if _, ok := policy.InvalidForGateways[gatewayNsName]; ok {
374				continue
375			}
376	
377			if !policy.Valid || policyKey.GVK.Kind != kinds.RateLimitPolicy {
378				continue
379			}
380	
381			var targetsGateway, targetsAttachedRoute bool
382	
383			// Check all target references in a single loop
384			for _, targetRef := range policy.TargetRefs {
385				// Check if targeting this gateway directly
386				if targetRef.Kind == kinds.Gateway && targetRef.Nsname == gatewayNsName {
387					targetsGateway = true
388					break // No need to check further if it targets the gateway
389				}
390	
391				// Check if targeting a route attached to this gateway
392				if targetRef.Kind == kinds.HTTPRoute || targetRef.Kind == kinds.GRPCRoute {
393					if _, exists := attachedRoutes[targetRef.Nsname]; exists {
394						targetsAttachedRoute = true
395						// Don't break here, we still need to check if any other targetRef targets the gateway
396					}
397				}
398			}
399	
400			// Only include policies that target attached routes but NOT the gateway
401			if targetsAttachedRoute && !targetsGateway {
402				referencedRateLimitPolicies[policyKey] = policy
403			}
404		}
405	
406		if len(referencedRateLimitPolicies) == 0 {
407			return nil
408		}
409	
410		return referencedRateLimitPolicies
411	}
412	
413	// isRouteAttachedToGateway checks if the given route is attached to this gateway.
414	// A route is considered attached if it references the gateway directly, or if it
415	// references a ListenerSet that is attached to this gateway.
416	func (g *Gateway) isRouteAttachedToGateway(route *L7Route, gatewayNsName types.NamespacedName) bool {
417		for _, parentRef := range route.ParentRefs {
418			if parentRef.Kind == kinds.Gateway && parentRef.NamespacedName == gatewayNsName {
419				return true
420			}
421	
422			if parentRef.Kind == kinds.ListenerSet {
423				if _, exists := g.AttachedListenerSets[parentRef.NamespacedName]; exists {
424					return true
425				}
426			}
427		}
428		return false
429	}
430	
431	// collectSnippetsFiltersFromRoute extracts SnippetsFilters from a single route's rules.
432	func (g *Gateway) collectSnippetsFiltersFromRoute(
433		route *L7Route,
434		allSnippetsFilters map[types.NamespacedName]*SnippetsFilter,
435		referencedFilters map[types.NamespacedName]*SnippetsFilter,
436	) {
437		for _, rule := range route.Spec.Rules {
438			if !rule.Filters.Valid {
439				continue
440			}
441	
442			for _, filter := range rule.Filters.Filters {
443				if filter.FilterType != FilterExtensionRef ||
444					filter.ResolvedExtensionRef == nil ||
445					filter.ResolvedExtensionRef.SnippetsFilter == nil {
446					continue
447				}
448	
449				sf := filter.ResolvedExtensionRef.SnippetsFilter
450				nsName := client.ObjectKeyFromObject(sf.Source)
451	
452				// Only include if it exists in the cluster-wide map and is valid
453				// Using the cluster-wide version ensures consistency and avoids duplicates
454				if clusterSF, exists := allSnippetsFilters[nsName]; exists && clusterSF.Valid {
455					referencedFilters[nsName] = clusterSF
456				}
457			}
458		}
459	}
460	
461	// buildProtectedPorts creates protected ports from an EffectiveNginxProxy configuration.
462	func buildProtectedPorts(effectiveNginxProxy *EffectiveNginxProxy) ProtectedPorts {
463		protectedPorts := make(ProtectedPorts)
464		if port, enabled := MetricsEnabledForNginxProxy(effectiveNginxProxy); enabled {
465			metricsPort := config.DefaultNginxMetricsPort
466			if port != nil {
467				metricsPort = *port
468			}
469			protectedPorts[metricsPort] = "MetricsPort"
470		}
471		return protectedPorts
472	}
473	
474	func validateUnsupportedGatewayFields(gw *v1.Gateway) []conditions.Condition {
475		var conds []conditions.Condition
476	
477		if gw.Spec.DefaultScope != "" {
478			conds = append(conds, conditions.NewGatewayAcceptedUnsupportedField(field.Forbidden(
479				field.NewPath("spec", "defaultScope"),
480				"DefaultScope",
481			).Error()))
482		}
483	
484		return conds
485	}
